namespace sv_00985505b27c4e3fb5e9183cb260464d.Client.Models;

public sealed class StatusUpdate
{
    public required DateTime Timestamp { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
}

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public required DateTime EstimatedDelivery { get; init; }
    public required List<StatusUpdate> Updates { get; init; }
}

using sv_00985505b27c4e3fb5e9183cb260464d.Client.Models;

namespace sv_00985505b27c4e3fb5e9183cb260464d.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_00985505b27c4e3fb5e9183cb260464d.Client.Models;
using sv_00985505b27c4e3fb5e9183cb260464d.Client.Services;

namespace sv_00985505b27c4e3fb5e9183cb260464d.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment
        {
            TrackingNumber = "TRK-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTime(2026, 6, 3),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 25, 8, 0, 0), Status = "Picked Up", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 26, 14, 30, 0), Status = "In Transit", Location = "Columbus, OH" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 27, 6, 15, 0), Status = "In Transit", Location = "Chicago, IL" },
            ]
        },
        ["TRK-002"] = new Shipment
        {
            TrackingNumber = "TRK-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTime(2026, 5, 26),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 22, 10, 0, 0), Status = "Picked Up", Location = "Seattle, WA" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 23, 16, 45, 0), Status = "In Transit", Location = "Portland, OR" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 25, 9, 0, 0), Status = "Out for Delivery", Location = "San Francisco, CA" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 25, 14, 20, 0), Status = "Delivered", Location = "San Francisco, CA" },
            ]
        },
        ["TRK-003"] = new Shipment
        {
            TrackingNumber = "TRK-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTime(2026, 6, 5),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 27, 7, 0, 0), Status = "Processing", Location = "Dallas, TX" },
            ]
        }
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);
        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_00985505b27c4e3fb5e9183cb260464d.Client.Models
@using sv_00985505b27c4e3fb5e9183cb260464d.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="alert alert-info" role="status">
        <span class="spinner-border spinner-border-sm" aria-hidden="true"></span>
        Loading shipment <strong>@TrackingNumber</strong>&hellip;
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning" role="alert">
        Shipment <strong>@TrackingNumber</strong> was not found.
    </div>
}
else
{
    <h3>Shipment @_shipment.TrackingNumber</h3>

    <dl class="row">
        <dt class="col-sm-3">Status</dt>
        <dd class="col-sm-9">@_shipment.Status</dd>

        <dt class="col-sm-3">Location</dt>
        <dd class="col-sm-9">@_shipment.Location</dd>

        <dt class="col-sm-3">Estimated Delivery</dt>
        <dd class="col-sm-9">@_shipment.EstimatedDelivery.ToShortDateString()</dd>
    </dl>

    <h4>Tracking History</h4>
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Time</th>
                <th>Status</th>
                <th>Location</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var update in _shipment.Updates)
            {
                <tr>
                    <td>@update.Timestamp.ToString("g")</td>
                    <td>@update.Status</td>
                    <td>@update.Location</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override Task OnParametersSetAsync() => LoadShipmentAsync();

    private async Task LoadShipmentAsync()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _shipment = null;
        _errorMessage = null;
        _loading = true;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — silently stop.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private Task RetryAsync() => LoadShipmentAsync();

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

